async fn retry<F>(mut op: F) -> Result<(), Error>
where
    F: AsyncFnMut() -> Result<(), Error>,
{
    for _ in 0..3 {
        if op().await.is_ok() {
            return Ok(());
        }
    }
    op().await
}

